// ../core/build/indexer/indexer.js
function indexFiles(db, files) {
  let indexed = 0;
  db.transaction(() => {
    for (const file of files) {
      db.execute(`INSERT INTO files (path, title, directory, tags, frontmatter, wiki_links, content, modified_at, indexed_at)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(path) DO UPDATE SET
           title = excluded.title,
           directory = excluded.directory,
           tags = excluded.tags,
           frontmatter = excluded.frontmatter,
           wiki_links = excluded.wiki_links,
           content = excluded.content,
           modified_at = excluded.modified_at,
           indexed_at = excluded.indexed_at`, [
        file.path,
        file.title,
        file.directory,
        JSON.stringify(file.tags),
        JSON.stringify(file.frontmatter),
        JSON.stringify(file.wikiLinks),
        file.content,
        file.modifiedAt,
        Date.now()
      ]);
      indexed++;
    }
  });
  return indexed;
}
function removeFile(db, path) {
  db.execute("DELETE FROM files WHERE path = ?", [path]);
}
function renameFile(db, oldPath, newPath) {
  const newTitle = newPath.split("/").pop()?.replace(/\.md$/, "") ?? newPath;
  const newDirectory = newPath.split("/")[0] ?? "";
  db.execute("UPDATE files SET path = ?, title = ?, directory = ? WHERE path = ?", [newPath, newTitle, newDirectory, oldPath]);
}
function deleteStaleFiles(db, existingPaths) {
  const dbFiles = db.queryAll("SELECT path FROM files");
  let deleted = 0;
  db.transaction(() => {
    for (const f of dbFiles) {
      if (!existingPaths.has(f.path)) {
        db.execute("DELETE FROM files WHERE path = ?", [f.path]);
        deleted++;
      }
    }
  });
  return deleted;
}

